// packages/database/src/db/schema/event.ts
// Drizzle table: event (generated by scripts/split-schema.ts)

import { createId } from '@paralleldrive/cuid2'
import { type AnyPgColumn, index, jsonb, pgTable, text, timestamp } from './_shared'

import { Organization } from './organization'

/** Drizzle table for event */
export const Event = pgTable(
  'Event',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    type: text().notNull(),
    data: jsonb().default({}).notNull(),
  },
  (table) => [
    index('Event_organizationId_idx').using('btree', table.organizationId.asc().nullsLast()),
    index('Event_type_idx').using('btree', table.type.asc().nullsLast()),
  ]
)

export type EventEntity = typeof Event.$inferSelect
export type CreateEventInput = typeof Event.$inferInsert
export type UpdateEventInput = Partial<CreateEventInput>
